changeSet.sql:
CREATE SEQUENCE IF NOT EXISTS speciality_id_seq; CREATE TABLE IF NOT EXISTS appointment_speciality ( speciality_id INTEGER NOT NULL DEFAULT nextval('speciality_id_seq'), name VARCHAR(50) NOT NULL, date_created TIMESTAMP NOT NULL, creator INTEGER NOT NULL, date_changed TIMESTAMP NULL, changed_by INTEGER NULL, uuid VARCHAR(38) NOT NULL UNIQUE, voided BOOLEAN DEFAULT FALSE, PRIMARY KEY (speciality_id) ); ALTER SEQUENCE speciality_id_seq OWNED BY appointment_speciality.speciality_id; CREATE UNIQUE INDEX IF NOT EXISTS appointment_speciality_name_unique ON appointment_speciality (name);
CREATE SEQUENCE IF NOT EXISTS appointment_service_id_seq; CREATE TABLE IF NOT EXISTS appointment_service ( appointment_service_id INTEGER NOT NULL DEFAULT nextval('appointment_service_id_seq'), name VARCHAR(50) NOT NULL, description TEXT NULL, start_time TIME NULL, end_time TIME NULL, location_id INTEGER NULL, speciality_id INTEGER NULL, max_appointments_limit INTEGER NULL, duration_mins INTEGER NULL, color VARCHAR(8) NULL, initial_appointment_status VARCHAR(45) NULL, date_created TIMESTAMP NOT NULL, creator INTEGER NOT NULL, date_changed TIMESTAMP NULL, changed_by INTEGER NULL, voided BOOLEAN DEFAULT FALSE, voided_by INTEGER NULL, date_voided TIMESTAMP NULL, void_reason VARCHAR(255) NULL, uuid VARCHAR(38) NOT NULL UNIQUE, PRIMARY KEY (appointment_service_id), CONSTRAINT fk_appointment_service_speciality FOREIGN KEY (speciality_id) REFERENCES appointment_speciality (speciality_id), CONSTRAINT fk_appointment_service_location FOREIGN KEY (location_id) REFERENCES location (location_id) ); ALTER SEQUENCE appointment_service_id_seq OWNED BY appointment_service.appointment_service_id; CREATE INDEX IF NOT EXISTS fk_appointment_service_speciality_idx ON appointment_service (speciality_id); CREATE INDEX IF NOT EXISTS fk_appointment_service_location_idx ON appointment_service (location_id); CREATE UNIQUE INDEX IF NOT EXISTS appointment_service_name_unique ON appointment_service (name);
CREATE SEQUENCE IF NOT EXISTS service_weekly_availability_seq; CREATE TABLE IF NOT EXISTS appointment_service_weekly_availability ( service_weekly_availability_id INTEGER NOT NULL DEFAULT nextval('service_weekly_availability_seq'), service_id INTEGER NOT NULL, day_of_week VARCHAR(45) NOT NULL, start_time TIME NULL, end_time TIME NULL, max_appointments_limit INTEGER NULL, uuid VARCHAR(38) NOT NULL UNIQUE, voided BOOLEAN DEFAULT FALSE, voided_by INTEGER NULL, date_voided TIMESTAMP NULL, void_reason VARCHAR(255) NULL, date_created TIMESTAMP NOT NULL, creator INTEGER NOT NULL, date_changed TIMESTAMP NULL, changed_by INTEGER NULL, PRIMARY KEY (service_weekly_availability_id), CONSTRAINT appointment_service FOREIGN KEY (service_id) REFERENCES appointment_service (appointment_service_id), CONSTRAINT service_enterer FOREIGN KEY (creator) REFERENCES users (user_id), CONSTRAINT user_who_deleted_service FOREIGN KEY (voided_by) REFERENCES users (user_id) ); ALTER SEQUENCE service_weekly_availability_seq OWNED BY appointment_service_weekly_availability.service_weekly_availability_id; CREATE INDEX IF NOT EXISTS fk_weekly_availability_appointment_service_idx ON appointment_service_weekly_availability (service_id);
CREATE SEQUENCE IF NOT EXISTS appointment_service_type_id_seq; CREATE TABLE IF NOT EXISTS appointment_service_type ( appointment_service_type_id INTEGER NOT NULL DEFAULT nextval('appointment_service_type_id_seq'), appointment_service_id INTEGER NOT NULL, name VARCHAR(50) NOT NULL, duration_mins INTEGER NULL, date_created TIMESTAMP NOT NULL, creator INTEGER NOT NULL, date_changed TIMESTAMP NULL, changed_by INTEGER NULL, voided BOOLEAN DEFAULT FALSE, voided_by INTEGER NULL, date_voided TIMESTAMP NULL, void_reason VARCHAR(255) NULL, uuid VARCHAR(38) NOT NULL UNIQUE, PRIMARY KEY (appointment_service_type_id), CONSTRAINT fk_appointment_service FOREIGN KEY (appointment_service_id) REFERENCES appointment_service (appointment_service_id) ); ALTER SEQUENCE appointment_service_type_id_seq OWNED BY appointment_service_type.appointment_service_type_id; CREATE INDEX IF NOT EXISTS fk_appointment_service_idx ON appointment_service_type (appointment_service_id); CREATE UNIQUE INDEX IF NOT EXISTS service_name_dur_UNIQUE ON appointment_service_type (appointment_service_id, name, duration_mins);
CREATE SEQUENCE IF NOT EXISTS patient_appointment_id_seq; CREATE TABLE IF NOT EXISTS patient_appointment ( patient_appointment_id INTEGER NOT NULL DEFAULT nextval('patient_appointment_id_seq'), provider_id INTEGER NULL, appointment_number VARCHAR(50) NOT NULL, patient_id INTEGER NOT NULL, start_date_time TIMESTAMP NULL, end_date_time TIMESTAMP NULL, appointment_service_id INTEGER NULL, appointment_service_type_id INTEGER NULL, status VARCHAR(45) NOT NULL, priority VARCHAR(45) NULL, location_id INTEGER NULL, appointment_kind VARCHAR(45) NOT NULL, comments VARCHAR(255) NULL, uuid VARCHAR(38) NOT NULL UNIQUE, date_created TIMESTAMP NOT NULL, date_appointment_scheduled TIMESTAMP NULL, creator INTEGER NOT NULL, date_changed TIMESTAMP NULL, changed_by INTEGER NULL, voided BOOLEAN NOT NULL DEFAULT FALSE, voided_by INTEGER NULL, date_voided TIMESTAMP NULL, void_reason VARCHAR(255) NULL, tele_health_video_link VARCHAR(255) NULL, related_appointment_id INTEGER NULL, PRIMARY KEY (patient_appointment_id), CONSTRAINT fk_patient_appointment_patient FOREIGN KEY (patient_id) REFERENCES patient (patient_id), CONSTRAINT fk_patient_appointment_location FOREIGN KEY (location_id) REFERENCES location (location_id), CONSTRAINT fk_patient_appointment_provider FOREIGN KEY (provider_id) REFERENCES provider (provider_id), CONSTRAINT fk_patient_appointment_appointment_service FOREIGN KEY (appointment_service_id) REFERENCES appointment_service (appointment_service_id), CONSTRAINT fk_patient_appointment_appointment_service_type FOREIGN KEY (appointment_service_type_id) REFERENCES appointment_service_type (appointment_service_type_id), CONSTRAINT patient_appointment_id_fk FOREIGN KEY (related_appointment_id) REFERENCES patient_appointment (patient_appointment_id) ); ALTER SEQUENCE patient_appointment_id_seq OWNED BY patient_appointment.patient_appointment_id;
CREATE SEQUENCE IF NOT EXISTS patient_appointment_audit_id_seq; CREATE TABLE IF NOT EXISTS patient_appointment_audit ( patient_appointment_audit_id INTEGER NOT NULL DEFAULT nextval('patient_appointment_audit_id_seq'), appointment_id INTEGER NOT NULL, uuid VARCHAR(38) NOT NULL UNIQUE, date_created TIMESTAMP NOT NULL, creator INTEGER NOT NULL, date_changed TIMESTAMP NULL, changed_by INTEGER NULL, voided BOOLEAN NOT NULL DEFAULT FALSE, voided_by INTEGER NULL, date_voided TIMESTAMP NULL, void_reason VARCHAR(255) NULL, status VARCHAR(45) NOT NULL, notes VARCHAR(1000) NULL, PRIMARY KEY (patient_appointment_audit_id), CONSTRAINT fk_patient_appointment_audit_patient_appointment FOREIGN KEY (appointment_id) REFERENCES patient_appointment (patient_appointment_id) ); ALTER SEQUENCE patient_appointment_audit_id_seq OWNED BY patient_appointment_audit.patient_appointment_audit_id; CREATE INDEX IF NOT EXISTS fk_patient_appointment_audit_patient_appointment_idx ON patient_appointment_audit (appointment_id);
CREATE TABLE IF NOT EXISTS patient_appointment_provider ( patient_appointment_provider_id INTEGER NOT NULL DEFAULT nextval('patient_appointment_audit_id_seq'), patient_appointment_id INTEGER NOT NULL, provider_id INTEGER NOT NULL, response VARCHAR(32) DEFAULT NULL, comments VARCHAR(1000) NULL, date_created TIMESTAMP NOT NULL, creator INTEGER NOT NULL, date_changed TIMESTAMP NULL, changed_by INTEGER NULL, voided BOOLEAN DEFAULT FALSE, voided_by INTEGER NULL, date_voided TIMESTAMP NULL, void_reason VARCHAR(255) NULL, uuid VARCHAR(38) NOT NULL UNIQUE, PRIMARY KEY (patient_appointment_provider_id), CONSTRAINT fk_patient_appointment_provider_patient_appointment FOREIGN KEY (patient_appointment_id) REFERENCES patient_appointment (patient_appointment_id), CONSTRAINT fk_patient_appointment_provider_provider FOREIGN KEY (provider_id) REFERENCES provider (provider_id) );
CREATE SEQUENCE IF NOT EXISTS patient_appointment_timings_id; CREATE TABLE IF NOT EXISTS patient_appointment_recurring_time ( patient_appointment_timings_id INTEGER NOT NULL DEFAULT nextval('patient_appointment_timings_id'), recurrence_type VARCHAR(20) NOT NULL, period INTEGER NOT NULL, frequency INTEGER NULL, end_date TIMESTAMP NULL, days_of_week VARCHAR(100) NULL, PRIMARY KEY (patient_appointment_timings_id) ); ALTER SEQUENCE patient_appointment_timings_id OWNED BY patient_appointment_recurring_time.patient_appointment_timings_id;
CREATE TABLE IF NOT EXISTS patient_appointment_occurrence ( patient_appointment_timings_id INTEGER NULL, patient_appointment_id INTEGER NULL, FOREIGN KEY (patient_appointment_timings_id) REFERENCES patient_appointment_recurring_time (patient_appointment_timings_id), FOREIGN KEY (patient_appointment_id) REFERENCES patient_appointment (patient_appointment_id) );

insert into patient_appointment_provider (patient_appointment_id, provider_id, response, date_created, creator, uuid)
select a.patient_appointment_id, a.provider_id, 'ACCEPTED', a.date_created, a.creator, uuid()
from patient_appointment a where a.provider_id is not null;

ALTER TABLE appointment_speciality MODIFY voided TINYINT(1) DEFAULT 0;
ALTER TABLE appointment_service MODIFY voided TINYINT(1) DEFAULT 0;
ALTER TABLE appointment_service_weekly_availability MODIFY voided TINYINT(1) DEFAULT 0;
ALTER TABLE appointment_service_type MODIFY voided TINYINT(1) DEFAULT 0;
ALTER TABLE patient_appointment MODIFY voided TINYINT(1) DEFAULT 0;
ALTER TABLE patient_appointment_audit MODIFY voided TINYINT(1) DEFAULT 0;
ALTER TABLE patient_appointment_provider MODIFY voided TINYINT(1) DEFAULT 0;

INSERT INTO privilege (privilege, description, uuid)
SELECT 'app:appointments:manageServiceAvailability', 'Able to Edit Appointment Service Availability in Appointments module', UUID()
WHERE NOT EXISTS (SELECT 1 FROM privilege WHERE privilege = 'app:appointments:manageServiceAvailability');

INSERT INTO privilege (privilege, description, uuid)
SELECT 'app:appointments:manageServices', 'Able to Manage Appointment Services in Appointments module', UUID()
WHERE NOT EXISTS (SELECT 1 FROM privilege WHERE privilege = 'app:appointments:manageServices');

INSERT INTO global_property (property, property_value, description, uuid)
SELECT 'disableDefaultAppointmentValidations', 'false', 'Disable default appointment validations', UUID()
WHERE NOT EXISTS (SELECT 1 FROM global_property WHERE property = 'disableDefaultAppointmentValidations');

INSERT INTO global_property (property, property_value, description, uuid)
SELECT 'SchedulerMarksComplete', 'false', 'Scheduler marks checked in appointments as complete when it turned on', UUID()
WHERE NOT EXISTS (SELECT 1 FROM global_property WHERE property = 'SchedulerMarksComplete');

INSERT INTO global_property (property, property_value, description, uuid)
SELECT 'SchedulerMarksMissed', 'false', 'Scheduler marks scheduled appointments as missed when it is turned on', UUID()
WHERE NOT EXISTS (SELECT 1 FROM global_property WHERE property = 'SchedulerMarksMissed');

INSERT INTO global_property (property, property_value, description, uuid)
SELECT 'SchedulerReminderBeforeHours', '24', 'How many hours before the appointment should the reminder SMS be sent', UUID()
WHERE NOT EXISTS (SELECT 1 FROM global_property WHERE property = 'SchedulerReminderBeforeHours');

INSERT INTO global_property (property, property_value, description, uuid)
SELECT 'bahmni.appointment.teleConsultation.patientEmailNotificationSubject', 'Teleconsultation appointment confirmed', 'Subject that will be used in the mail sent to patients for Teleconsultation', UUID()
WHERE NOT EXISTS (SELECT 1 FROM global_property WHERE property = 'bahmni.appointment.teleConsultation.patientEmailNotificationSubject');

INSERT INTO global_property (property, property_value, description, uuid)
SELECT 'bahmni.appointment.teleConsultation.patientEmailNotificationTemplate', 'Hi {0}, Your tele-consultation appointment with {1} for {2} has been scheduled! Please use this link {3}. If you have any questions, please reach out to administration for assistance. See you soon!', 'Template to use while sending mail. Format is define like in Java MessageFormat', UUID()
WHERE NOT EXISTS (SELECT 1 FROM global_property WHERE property = 'bahmni.appointment.teleConsultation.patientEmailNotificationTemplate');

INSERT INTO global_property (property, property_value, description, uuid)
SELECT 'bahmni.appointment.teleConsultation.serverUrlPattern', 'https://meet.jit.si/{0}', 'Pattern of the URL for the meeting server. Notice the placeholder {0} for appointment UUID', UUID()
WHERE NOT EXISTS (SELECT 1 FROM global_property WHERE property = 'bahmni.appointment.teleConsultation.serverUrlPattern');

INSERT INTO global_property (property, property_value, description, uuid)
SELECT 'bahmni.appointment.teleConsultation.sendEmail', 'false', 'Whether email should be sent for tele-consultation', UUID()
WHERE NOT EXISTS (SELECT 1 FROM global_property WHERE property = 'bahmni.appointment.teleConsultation.sendEmail');

INSERT INTO global_property (property, property_value, description, uuid)
SELECT 'bahmni.appointment.adhocTeleConsultation.patientEmailNotificationSubject', 'Teleconsultation started', 'Subject that will be used in the mail sent to patients for AdhocTeleconsultation', UUID()
WHERE NOT EXISTS (SELECT 1 FROM global_property WHERE property = 'bahmni.appointment.adhocTeleConsultation.patientEmailNotificationSubject');

INSERT INTO global_property (property, property_value, description, uuid)
SELECT 'bahmni.appointment.adhocTeleConsultation.patientEmailNotificationTemplate', 'Hi {0}, {1} has started a tele-consultation with you! Please use this link {2}. If you have any questions, please reach out to administration for assistance. See you soon!', 'Template to use while sending mail for AdhocTeleconsultation. Format is define like in Java MessageFormat', UUID()
WHERE NOT EXISTS (SELECT 1 FROM global_property WHERE property = 'bahmni.appointment.adhocTeleConsultation.patientEmailNotificationTemplate');

INSERT INTO global_property (property, property_value, description, uuid)
SELECT 'bahmni.appointment.adhocTeleConsultation.bccEmails', '', 'BCC Emails for AdhocTeleconsultation', UUID()
WHERE NOT EXISTS (SELECT 1 FROM global_property WHERE property = 'bahmni.appointment.adhocTeleConsultation.bccEmails');

INSERT INTO global_property (property, property_value, description, uuid)
SELECT 'bahmni.adhoc.teleConsultation.id', 'Patient Identifier', 'Identifier type of patient to generate AdhocTeleconsultation link eg: ''Patient Identifier'' or ''National ID'' etc', UUID()
WHERE NOT EXISTS (SELECT 1 FROM global_property WHERE property = 'bahmni.adhoc.teleConsultation.id');

INSERT INTO global_property (property, property_value, description, uuid)
SELECT 'sms.enableAppointmentBookingSMSAlert', 'false', 'Whether SMS should be sent for appointment booking', UUID()
WHERE NOT EXISTS (SELECT 1 FROM global_property WHERE property = 'sms.enableAppointmentBookingSMSAlert');

INSERT INTO global_property (property, property_value, description, uuid)
SELECT 'sms.enableAppointmentReminderSMSAlert', 'false', 'Whether SMS should be sent for appointment reminders', UUID()
WHERE NOT EXISTS (SELECT 1 FROM global_property WHERE property = 'sms.enableAppointmentReminderSMSAlert');

INSERT INTO global_property (property, property_value, description, uuid)
SELECT 'sms.timezone', 'IST', 'Timezone used for appointment SMS messages', UUID()
WHERE NOT EXISTS (SELECT 1 FROM global_property WHERE property = 'sms.timezone');

INSERT INTO global_property (property, property_value, description, uuid)
SELECT 'sms.dateformat', 'dd-MM-yyyy'' Time ''HH:mm', 'Date format used for appointment SMS messages', UUID()
WHERE NOT EXISTS (SELECT 1 FROM global_property WHERE property = 'sms.dateformat');

DO $$
BEGIN
  CREATE SEQUENCE IF NOT EXISTS speciality_id_seq INCREMENT BY 50;
  ALTER SEQUENCE speciality_id_seq INCREMENT BY 50;
  PERFORM setval('speciality_id_seq', GREATEST((SELECT COALESCE(MAX(speciality_id), 0) + 50 FROM appointment_speciality), 50), true);

  CREATE SEQUENCE IF NOT EXISTS appointment_service_id_seq INCREMENT BY 50;
  ALTER SEQUENCE appointment_service_id_seq INCREMENT BY 50;
  PERFORM setval('appointment_service_id_seq', GREATEST((SELECT COALESCE(MAX(appointment_service_id), 0) + 50 FROM appointment_service), 50), true);

  CREATE SEQUENCE IF NOT EXISTS service_weekly_availability_seq INCREMENT BY 50;
  ALTER SEQUENCE service_weekly_availability_seq INCREMENT BY 50;
  PERFORM setval('service_weekly_availability_seq', GREATEST((SELECT COALESCE(MAX(service_weekly_availability_id), 0) + 50 FROM appointment_service_weekly_availability), 50), true);

  CREATE SEQUENCE IF NOT EXISTS appointment_service_type_id_seq INCREMENT BY 50;
  ALTER SEQUENCE appointment_service_type_id_seq INCREMENT BY 50;
  PERFORM setval('appointment_service_type_id_seq', GREATEST((SELECT COALESCE(MAX(appointment_service_type_id), 0) + 50 FROM appointment_service_type), 50), true);

  CREATE SEQUENCE IF NOT EXISTS patient_appointment_id_seq INCREMENT BY 50;
  ALTER SEQUENCE patient_appointment_id_seq INCREMENT BY 50;
  PERFORM setval('patient_appointment_id_seq', GREATEST((SELECT COALESCE(MAX(patient_appointment_id), 0) + 50 FROM patient_appointment), 50), true);

  CREATE SEQUENCE IF NOT EXISTS patient_appointment_audit_id_seq INCREMENT BY 50;
  ALTER SEQUENCE patient_appointment_audit_id_seq INCREMENT BY 50;
  PERFORM setval(
    'patient_appointment_audit_id_seq',
    GREATEST(
      (SELECT COALESCE(MAX(patient_appointment_audit_id), 0) FROM patient_appointment_audit),
      (SELECT COALESCE(MAX(patient_appointment_provider_id), 0) FROM patient_appointment_provider)
    ) + 50,
    true
  );

  CREATE SEQUENCE IF NOT EXISTS patient_appointment_timings_id INCREMENT BY 50;
  ALTER SEQUENCE patient_appointment_timings_id INCREMENT BY 50;
  PERFORM setval('patient_appointment_timings_id', GREATEST((SELECT COALESCE(MAX(patient_appointment_timings_id), 0) + 50 FROM patient_appointment_recurring_time), 50), true);

  CREATE SEQUENCE IF NOT EXISTS patient_appointment_reason_id_seq INCREMENT BY 50;
  ALTER SEQUENCE patient_appointment_reason_id_seq INCREMENT BY 50;
  PERFORM setval('patient_appointment_reason_id_seq', GREATEST((SELECT COALESCE(MAX(patient_appointment_reason_id), 0) + 50 FROM patient_appointment_reason), 50), true);

  CREATE SEQUENCE IF NOT EXISTS appointment_service_attribute_type_id_seq INCREMENT BY 50;
  ALTER SEQUENCE appointment_service_attribute_type_id_seq INCREMENT BY 50;
  PERFORM setval('appointment_service_attribute_type_id_seq', GREATEST((SELECT COALESCE(MAX(appointment_service_attribute_type_id), 0) + 50 FROM appointment_service_attribute_type), 50), true);

  CREATE SEQUENCE IF NOT EXISTS appointment_service_attribute_id_seq INCREMENT BY 50;
  ALTER SEQUENCE appointment_service_attribute_id_seq INCREMENT BY 50;
  PERFORM setval('appointment_service_attribute_id_seq', GREATEST((SELECT COALESCE(MAX(appointment_service_attribute_id), 0) + 50 FROM appointment_service_attribute), 50), true);
END $$;
